CREATE TABLE public.files (
	"index" int4 GENERATED BY DEFAULT AS IDENTITY( INCREMENT BY 1 MINVALUE 1 MAXVALUE 2147483647 START 1 CACHE 1 NO CYCLE) NOT NULL,
	original_name text NOT NULL,
	stored_name text NOT NULL,
	file_path text NOT NULL,
	file_size int8 NOT NULL,
	reg_date timestamp DEFAULT now() NULL,
	board_index int4 NOT NULL,
	deleted_at timestamp NULL,
	CONSTRAINT files_pkey PRIMARY KEY (index),
	CONSTRAINT fk_files_board_index FOREIGN KEY (board_index) REFERENCES public.boards("index") ON DELETE CASCADE
);